import React from 'react';

interface HomeProps {
  navigate: (page: string) => void;
}

const navBtnStyle: React.CSSProperties = {
  padding: '6px 20px',
  background: '#c0c0c0',
  borderTop: '2px solid #ffffff',
  borderLeft: '2px solid #ffffff',
  borderRight: '2px solid #404040',
  borderBottom: '2px solid #404040',
  cursor: 'pointer',
  fontSize: 12,
  fontWeight: 'bold',
  letterSpacing: 1,
};

const Home: React.FC<HomeProps> = ({ navigate }) => {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', padding: 40, textAlign: 'center' }}>
      <h1 style={{ fontSize: 52, fontFamily: 'Georgia, serif', marginBottom: 8, lineHeight: 1 }}>Raghv Bhatia</h1>
      <h2 style={{ fontSize: 18, fontWeight: 'normal', color: '#333', marginBottom: 48 }}>Digital Experience Partner</h2>
      <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap', justifyContent: 'center' }}>
        <button style={navBtnStyle} onClick={() => navigate('about')}>ABOUT</button>
        <button style={navBtnStyle} onClick={() => navigate('experience')}>EXPERIENCE</button>
        <button style={navBtnStyle} onClick={() => navigate('skills')}>SKILLS</button>
        <button style={navBtnStyle} onClick={() => navigate('contact')}>CONTACT</button>
      </div>
    </div>
  );
};

export default Home;
